"use strict";parserFactory.register("cangji.net",()=>new CangjiParser);class CangjiParser extends Parser{constructor(){super()}async getChapterUrls(e,t){return await this.walkTocPages(e,CangjiParser.chaptersFromDom,CangjiParser.nextTocPageUrl,t)}static chaptersFromDom(e){return[...e.querySelectorAll("#content .entry-title a")].map(e=>util.hyperLinkToChapter(e))}static nextTocPageUrl(e){let t=e.querySelector("a.next");return null===t?null:t.href}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector("h1.archive-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".post-tags, .wp-block-ugb-container"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("h1.entry-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div.post-img")}}